#nullable enable // autogenerated

using System.Collections.Generic;
using System.Xml;

namespace MVZ2.Metas
{
    public class OptionMetaList
    {
        public OptionCategoryMeta[] categories;
        public OptionItemMeta[] items;
        public OptionWidgetMeta[] widgets;

        public OptionMetaList(OptionCategoryMeta[] categories, OptionItemMeta[] items, OptionWidgetMeta[] widgets)
        {
            this.categories = categories;
            this.items = items;
            this.widgets = widgets;
        }

        public static OptionMetaList FromXmlNode(XmlNode node, string defaultNsp)
        {
            var categories = new List<OptionCategoryMeta>();
            var categoriesNode = node["categories"];
            if (categoriesNode != null)
            {
                for (int i = 0; i < categoriesNode.ChildNodes.Count; i++)
                {
                    var childNode = categoriesNode.ChildNodes[i];
                    switch (childNode.Name)
                    {
                        case "category":
                            var meta = OptionCategoryMeta.FromXmlNode(childNode, defaultNsp);
                            if (meta != null)
                                categories.Add(meta);
                            break;
                    }
                }
            }
            var items = new List<OptionItemMeta>();
            var itemsNode = node["items"];
            if (itemsNode != null)
            {
                for (int i = 0; i < itemsNode.ChildNodes.Count; i++)
                {
                    var childNode = itemsNode.ChildNodes[i];
                    var item = OptionItemMeta.FromXmlNode(childNode, defaultNsp);
                    if (item != null)
                        items.Add(item);
                }
            }
            var widgets = new List<OptionWidgetMeta>();
            var widgetsNode = node["widgets"];
            if (widgetsNode != null)
            {
                for (int i = 0; i < widgetsNode.ChildNodes.Count; i++)
                {
                    var childNode = widgetsNode.ChildNodes[i];
                    var widget = OptionWidgetMeta.FromXmlNode(childNode, defaultNsp, i);
                    if (widget != null)
                        widgets.Add(widget);
                }
            }
            return new OptionMetaList(categories.ToArray(), items.ToArray(), widgets.ToArray());
        }
    }
}
